+TEST_F(TestPinocchioPlugin, incorrect_input_sizes)
+{
+  // load robot description and alpha to parameter server
+  loadURDFParameter();
+  loadAlphaParameter();
+
+  // initialize the  plugin
+  ASSERT_TRUE(ik_->initialize(node_->get_node_parameters_interface(), end_effector_));
